import { Component, Host, Prop, State, h, Event, EventEmitter, Method, Listen, Element, Watch } from '@stencil/core';
import { MxVerticalNavItemCustomEvent } from '@src/components';
import { addGlobalStylesToShadowRoot, isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { hideAllSubmenus } from '../mx-vertical-nav-sub-menu/mx-vertical-nav-sub-menu-utils';
import { IVerticalNavItem } from '../mx-vertical-nav.interface';

export interface IVerticalNavPanelItem extends IVerticalNavItem {
  columns?: number;
}

@Component({
  tag: 'mx-vertical-nav-panel',
  styleUrl: 'mx-vertical-nav-panel.css',
  shadow: true
})
export class MxVerticalNavPanel {

  @Element() hostElement: HTMLMxVerticalNavPanelElement;

  /** Sets the items of the vertical navigation panel. */
  @Prop() readonly items!: Array<IVerticalNavPanelItem>;

  @Watch('items')
  onItemsChange(newValue: IVerticalNavItem[]) {
    this._items = this._levelOrder(newValue);
    this.updateHamburgerMenuShownStatus.emit(this._items.length > 0);
  }

  /** Keeps the panel with opened. Clicks outside the navigation panel will be ignored. */
  @Prop() readonly keepPanelOpen: boolean;
  /** Navigation panel open state  */
  @Prop({ mutable: true }) opened = false;

  @State() _items: IVerticalNavPanelItem[];

  /** Event that fires when navigation panel open state changes  */
  @Event() openChange: EventEmitter;
  /** Emits an event when the component loads to determine if the hamburger icon for the nav header should be shown or not.  */
  @Event() updateHamburgerMenuShownStatus: EventEmitter<boolean>;

  /** Opens the vertical navigation panel. */
  @Method()
  async openPanel() {
    this.changeOpen(true);
  }

  /** Closes the vertical navigation panel. */
  @Method()
  async closePanel() {
    this.changeOpen(false);
  }

  private panelElement: HTMLElement;
  // Need to throttle scroll event
  private scrollTick = false;

  @Listen('click', { target: 'document', capture: true })
  handleOutsideClick(event: MouseEvent) {
    this.handleOutsidePanelClick(event);
  }

  componentWillLoad() {
    if (!isNullOrUndefined(this.items)) {
      this._items = this._levelOrder(this.items);
      this.updateHamburgerMenuShownStatus.emit(this._items.length > 0);
    }
    this.hostElement.shadowRoot && addGlobalStylesToShadowRoot(this.hostElement.shadowRoot);
  }

  componentDidLoad() {
    this.handleScrollablePanel();
  }

  /** We need a way to track whether the user has clicked on the scrollbar. There's no native way of doing this.
   We need it to happen because of an edge case where the user can hover over the scroll bar before they get to the sub-element,
   and start scrolling. The sub-menu will not disappear in this case without the following code. */
  private handleScrollablePanel() {
    const isScrollable = this.panelElement.scrollHeight > this.panelElement.clientHeight;
    if (isScrollable) {
      this.panelElement.addEventListener('mousedown', (event: MouseEvent) => {
        const mouseDownPosition = event.clientX;
        const panelWidthWithoutScrollbar = this.panelElement.clientWidth;
        if (mouseDownPosition > panelWidthWithoutScrollbar) {
          hideAllSubmenus();
        }
      });
      // We need to throttle the scroll event a bit so it doesn't fire off hundreds of times.
      this.panelElement.addEventListener('scroll', () => {
        if (!this.scrollTick) {
          setTimeout(() => {
            this.scrollTick = false;
            hideAllSubmenus();
          }, 50);
        }
        this.scrollTick = true;
      });
    }
  }

  /** recursive call to child node **/
  private readonly _levelOrder = (menuData) => {
    if (isNullOrUndefined(menuData)) {
      return;
    }
    return menuData.map((item) => {
      if (!Array.isArray(item.children) || !item.children.length) { // check if item is array
        const shouldHide: boolean = item.shouldHide || item.link == null;
        return shouldHide ? undefined : {
          ...item,
          shouldHide
        };
      } else {
        const shouldHide: boolean = item.shouldHide || this._shouldHide(item.children);

        return shouldHide ? undefined : {
          ...item,
          shouldHide,
          children: this._levelOrder(item.children)
        };
      }
    }).filter((element) => element !== undefined);
  };

  /** check if all below child is valid with link and should hide **/
  private readonly _shouldHide = (menuData): boolean => {
    if (isNullOrUndefined(menuData)) {
      return;
    }
    return menuData.map((item) => {
      if (!Array.isArray(item.children) || !item.children.length) {
        return item.shouldHide || item.link == null;
      } else {
        return item.shouldHide || this._shouldHide(item.children);
      }
    }).every(Boolean);  // shorthand for (item)=> item == true
  };

  private readonly handleOutsidePanelClick = (event: MouseEvent) => {
    if (this.keepPanelOpen) {
      return;
    }

    const hamburgerButton = this.hostElement.parentElement.querySelector('mx-vertical-nav-header')
      .shadowRoot.querySelector('.mx-vertical-nav__menu-btn');

    if (!isNullOrUndefined(hamburgerButton) && event.composedPath().includes(hamburgerButton)) {
      return;
    }

    if (this.opened && !event.composedPath().includes(this.panelElement)) {
      // We need to update mx-vertical-nav-header's hamburger menu icon if the consumer is using it
      const verticalNavHeaderRef = this.hostElement.parentElement.querySelector('mx-vertical-nav-header');
      if (!isNullOrUndefined(verticalNavHeaderRef)) {
        verticalNavHeaderRef.setMenuOpenStatus(false);
      }
      this.changeOpen(false);
    }
  };

  private readonly changeOpen = (opened: boolean) => {
    this.opened = opened;
    this.openChange.emit(this.opened);
    if (!this.opened) {
      // Let's wait for the animation to finish before we set the scrollTop to 0.
      // If we don't wait, the animation will be incorrect when the user has scrolled.
      // The animation is set to 0.3 seconds. i.e 300ms.
      // Listening to "animationend" is not working for some reason.
      setTimeout(() => this.panelElement.scrollTop = 0, 300);
      // Let's hide any sub-menus if they are still open
      hideAllSubmenus();
      // Let's check if the consumer has opted in for the vertical-nav-header(these components can be used independently).
      // If so, we need to update the menu icon.
      const verticalNavHeader = this.hostElement.parentElement.querySelector('mx-vertical-nav-header');
      if (!isNullOrUndefined(verticalNavHeader)) {
        verticalNavHeader.setMenuOpenStatus(false);
      }
    } else {
      // Scroll to selected element.
      this.hostElement.shadowRoot.querySelector('.mx-vertical-nav-item_selected')?.scrollIntoView(
        { behavior: "smooth", block: "center", inline: "center" });
    }
  };

  private readonly onVerticalNavClick = (event: MxVerticalNavItemCustomEvent<IVerticalNavItem>) => {
    const currentItem: IVerticalNavItem = event.detail;
    const hasChildren: boolean = currentItem.hasOwnProperty('children') &&
      currentItem.children.length > 0;
    const closeOnclick: boolean = currentItem.closeOnclick || currentItem['closePanelOnclick'];
    if (!hasChildren && closeOnclick) {
      this.changeOpen(false);
    }
  };

  render() {
    return (
      <Host class={{
        'mx-vertical-nav__wrapper': true,
        'mx-vertical-nav__wrapper_opened': this.opened
      }}>
        <div
          ref={(ref: HTMLElement) => this.panelElement = ref}
          class={{
            'mx-vertical-nav__panel text-primary': true,
            'mx-vertical-nav__panel_opened bg-neutral-most-subtle': this.opened
          }}>
          {
            !isNullOrUndefined(this._items) && this._items.length > 0 ?
              <ul class='mx-vertical-nav__list'>
                {
                  this._items.map((item: IVerticalNavPanelItem) => {
                    return item.isDivider ?
                      <hr/> :
                      <mx-vertical-nav-item
                        class='mx-vertical-nav__list-item'
                        columns={item.columns}
                        onClickHandler={this.onVerticalNavClick}
                        item={{ ...item }}/>;
                  })
                }
              </ul> : ''
          }
        </div>
        <div class={{
          'mx-vertical-nav__content': true,
          'mx-vertical-nav__content_opened': this.opened
        }}>
          <slot />
        </div>
      </Host>
    );
  }
}
