/* eslint-disable max-len */
import { Component, Host, Prop, State, h, Event, EventEmitter, Element, Listen, Method } from '@stencil/core';
import { addGlobalStylesToShadowRoot, isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { IVerticalNavUserMenuItem } from '../mx-vertical-nav.interface';

@Component({
  tag: 'mx-vertical-nav-header',
  styleUrl: 'mx-vertical-nav-header.css',
  shadow: true
})
export class MxVerticalNavHeader {

  @Element() hostElement: HTMLMxVerticalNavHeaderElement;

  /** Sets the app title in the top bar. */
  @Prop() readonly appTitle: string;
  /** Shows/hides the hamburger menu. */
  @Prop() readonly showHamburgerMenu: boolean = false;
  /** Sets the items of the user menu in the popup on user click. */
  @Prop () readonly userItems: Array<IVerticalNavUserMenuItem>;
  /** Navigation panel open state  */
  @Prop({ mutable: true }) opened = false;

  /** User menu open state  */
  @State() userMenuOpened = false;

  /**  Handler for the click of the logo */
  @Event() logoClick: EventEmitter;
  /**  This event is emitted in case the user clicks on the app title. */
  @Event() titleClick: EventEmitter;
  /**  Emits an event whenever the hamburger menu icon is clicked. Returns the opened status. */
  @Event() hamburgerMenuClick: EventEmitter<boolean>;
  /**  Emits an event whenever the user profile item is clicked.  */
  @Event() userProfileItemSelected: EventEmitter<IVerticalNavUserMenuItem>;


  @Listen('click', { target: 'document', capture: true })
  handleOutsideClick(event) {
    this.handleOutsideUserMenuClick(event);
  }

  private readonly handleOutsideUserMenuClick = (event) => {
    if (!this.userMenuOpened) {
      return;
    }
    const userMenuButton = this.hostElement.shadowRoot.querySelector('.mx-vertical-nav__user-btn');
    if (event.target === userMenuButton || event.composedPath().includes( userMenuButton)) {
      return;
    }

    const userMenu = this.hostElement.shadowRoot.querySelector('.mx-vertical-nav__user-menu-container');
    if (event.target !== userMenu && !event.composedPath().includes(userMenu)) {
      this.userMenuOpened = false;
    }
  };

  /** Sets the hamburger menu's opened status to true or false. */
  @Method()
  async setMenuOpenStatus(status: boolean) {
    this.opened = status;
  }

  componentWillLoad() {
    this.hostElement.shadowRoot && addGlobalStylesToShadowRoot(this.hostElement.shadowRoot);
  }

  private readonly toggleHamburgerMenu = () => {
    this.opened = !this.opened;
    this.hamburgerMenuClick.emit(this.opened);
  };

  private readonly onNavLogoClick = () => {
    this.logoClick.emit();
  };

  private readonly onNavTitleClick = () => {
    this.titleClick.emit();
  };

  private readonly onUserProfileMenuActionClick = (ui: IVerticalNavUserMenuItem) => (_event: MouseEvent) => {
    if (ui.closeOnclick) {
      this.userMenuOpened = false;
    }
    if (!isNullOrUndefined(ui.clickHandler)) {
      ui.clickHandler();
      this.userProfileItemSelected.emit(ui);
    }
  };

  render() {
    return (
      <Host>
        <header class='mx-vertical-nav__header bg-brand-more-prominent text-primary-inverse'>
          {
            this.showHamburgerMenu ?
              <kds-button
                class='mx-vertical-nav__menu-btn'
                type='button'
                onClick={this.toggleHamburgerMenu}
                variant='border'
                inverse>
                <div class={{
                  'mx-vertical-nav__btn-lines': true,
                  'mx-vertical-nav__btn-lines_opened': this.opened
                }}>
                  <div class={{
                    'mx-vertical-nav__menu-btn-line': true,
                    'bg-primary': !this.opened,
                    'bg-opacity-transparent': this.opened
                  }}></div>
                  <div class={{
                    'mx-vertical-nav__menu-btn-line': true,
                    'bg-primary': !this.opened,
                    'bg-opacity-transparent': this.opened
                  }}></div>
                  <div class={{
                    'mx-vertical-nav__menu-btn-line': true,
                    'bg-primary': !this.opened,
                    'bg-opacity-transparent': this.opened
                  }}></div>
                </div>
              </kds-button> : <span></span>
          }

          <button
            class={{
              'mx-vertical-nav__logo': true,
              'mx-vertical-nav__logo_no-hamburger': !this.showHamburgerMenu
            }}
            onClick={this.onNavLogoClick}>

            {
              (this.hostElement.querySelector('[name="logo"]') as HTMLSlotElement)?.assignedNodes().length === 0  ?
                <img
                  src='data:image/svg+xml;base64,'
                  style={{ height: '36px' }}
                  alt='The Kroger logo'></img>:
                <slot name='inner-logo'></slot>
            }
          </button>
          <div class='pl-24' id='app-title-wrapper'>
            <kds-link
              linkClass='no-underline'
              onClick={this.onNavTitleClick}
              inverse
              implied
              class='mx-vertical-nav__app-title'>
              {this.appTitle}
            </kds-link>
          </div>

          <div class='mx-vertical-nav__right-block'>
            <div class='mx-vertical-nav__custom'>
              <slot name='inner-center-block'></slot>
            </div>

            {
              (this.hostElement.querySelector('[name=user]') as HTMLSlotElement)?.assignedNodes().length === 0  ?
                <span /> :
                <div class='mx-vertical-nav__user'>
                  <button
                    type='button'
                    class={{
                      'mx-vertical-nav__user-btn': true,
                      'mx-vertical-nav__user-btn_opened': this.userMenuOpened
                    }}
                    onClick={() => this.userMenuOpened = !this.userMenuOpened}>
                    <div class='mx-vertical-nav__user-avatar border border-primary'>
                      <slot name='inner-user' >
                      </slot>
                    </div>
                  </button>
                  {
                    !this.userMenuOpened ?
                      <span /> :
                      <div class='mx-vertical-nav__user-menu-container'>
                        <div class='mx-vertical-nav__user-menu bg-primary border border-primary-inverse border-opacity-moreTransparent'>
                          {
                            this.userItems && this.userItems.map((ui: IVerticalNavUserMenuItem, index) => {
                              return <div class={{
                                'mx-vertical-nav__user-menu-item bg-primary text-primary hover:bg-accent-less-subtle': true,
                                'mx-vertical-nav__user-menu-item_with-icon': ui.icon != null

                              }}>
                                <span class={{
                                  'user-menu-item__selection-bar bg-brand-more-prominent bg-opacity-transparent': true,
                                  'user-menu-item__selection-bar-active bg-opacity-opaque': ui.selected
                                }}/>
                                { index === 0 ?
                                  <span
                                    class='mx-vertical-nav__user-menu-header-label bg-secondary text-tertiary border-b border-primary-inverse border-opacity-moreTransparent'
                                    title={ui.label}>{ui.label}</span> :
                                  <button
                                    type='button'
                                    onClick={this.onUserProfileMenuActionClick(ui)}
                                    disabled={index===0}>
                                    {ui.icon == null ?
                                      <span /> :
                                      <div class='mx-vertical-nav__user-menu-item-icon'>
                                        {h(ui.icon, { size: 's' })}
                                      </div>
                                    }
                                    <span class='mx-vertical-nav__user-menu-item-label'>{ui.label}</span>
                                  </button>
                                }

                              </div>;
                            })
                          }
                        </div>
                      </div>
                  }
                </div>
            }
          </div>
        </header>
      </Host>
    );
  }

}
